"use server";

import { clientService } from "@/services/client.service";
import { getCurrentUser } from "@/lib/auth/session";
import { PAGINATION } from "@/lib/constants";
import type { ClientFilterValue, ClientSortValue } from "@/lib/validations/client";

/* ============================================
   Get Clients Server Action
   Paginated list with search, filter, and sort.
   ============================================ */

export async function getClientsAction(params?: {
  page?: number;
  pageSize?: number;
  search?: string;
  filter?: ClientFilterValue;
  sort?: ClientSortValue;
}) {
  const user = await getCurrentUser();
  if (!user) {
    return {
      items: [],
      total: 0,
      page: 1,
      pageSize: PAGINATION.DEFAULT_PAGE_SIZE,
      totalPages: 0,
    };
  }

  const page = params?.page ?? PAGINATION.DEFAULT_PAGE;
  const pageSize = params?.pageSize ?? 10;
  const skip = (page - 1) * pageSize;

  const { items, total } = await clientService.list({
    userId: user.id,
    skip,
    take: pageSize,
    search: params?.search,
    filter: params?.filter ?? "all",
    sort: params?.sort ?? "newest",
  });

  const totalPages = Math.ceil(total / pageSize);

  return {
    items: items.map((c) => ({
      id: c.id,
      clientCode: c.clientCode,
      name: c.name,
      company: c.company,
      phone: c.phone,
      email: c.email,
      notes: c.notes,
      status: c.status,
      archivedAt: c.archivedAt,
      projectCount: c._count.projects,
      createdAt: c.createdAt,
      updatedAt: c.updatedAt,
    })),
    total,
    page,
    pageSize,
    totalPages,
  };
}

"use server";

import { createSupabaseAdminClient } from "@/lib/supabase/admin";
import { userRepository } from "@/repositories/user.repository";
import { registerSchema } from "@/lib/validations/auth";
import type { AuthenticatedUser } from "@/types/auth";

/* ============================================
   Register Server Action
   Creates a new user in Supabase Auth, then
   creates the corresponding Prisma profile.
   ============================================ */

export type RegisterState = {
  success: boolean;
  error?: string;
  user?: AuthenticatedUser;
};

export async function registerAction(
  _prev: RegisterState,
  formData: FormData
): Promise<RegisterState> {
  const raw = {
    name: formData.get("name"),
    email: formData.get("email"),
    password: formData.get("password"),
    confirmPassword: formData.get("confirmPassword"),
  };

  const parsed = registerSchema.safeParse(raw);

  if (!parsed.success) {
    return {
      success: false,
      error: parsed.error.issues[0]?.message ?? "ž©┘Ŗž¦┘åž¦ž¬ ž║┘Ŗž▒ žĄž¦┘äžŁž®",
    };
  }

  const { name, email, password } = parsed.data;

  // Check if email is already registered in Prisma
  const existing = await userRepository.findByEmail(email);
  if (existing) {
    return { success: false, error: "ž¦┘äž©ž▒┘Ŗž» ž¦┘äžź┘ä┘āž¬ž▒┘ł┘å┘Ŗ ┘ģž│ž¬ž«ž»┘ģ ž©ž¦┘ä┘üž╣┘ä" };
  }

  // Create user in Supabase Auth
  const supabaseAdmin = createSupabaseAdminClient();
  const { data, error } = await supabaseAdmin.auth.admin.createUser({
    email,
    password,
    email_confirm: true,
    user_metadata: { name },
  });

  if (error || !data.user) {
    return {
      success: false,
      error: "┘üž┤┘ä ┘ü┘Ŗ žź┘åž┤ž¦žĪ ž¦┘äžŁž│ž¦ž©. ┘Ŗž▒ž¼┘ē ž¦┘ä┘ģžŁž¦┘ł┘äž® ┘ģž▒ž® žŻž«ž▒┘ē.",
    };
  }

  // Create Prisma profile linked to Supabase Auth user
  const user = await userRepository.create({
    email,
    name,
    supabaseUid: data.user.id,
    role: "PHOTOGRAPHER",
  });

  return {
    success: true,
    user: {
      id: user.id,
      email: user.email,
      name: user.name,
      role: user.role,
      avatar: user.avatar,
    },
  };
}

